import React, { useRef } from 'react'
import { useTranslation } from 'react-i18next'
import { ContactOverlay } from '@fs/zion-contact-overlay'
import { ListItem, useOverlay } from '@fs/zion-ui'
import { i18n } from '@fs/zion-locale'
import { chatAvatar } from '../chat-avatar/chatAvatar'
import { getPortraitUrlFromCisId } from '../helpers/portraitServiceHelper'
import ChatPersonMenuOverlay from './ChatPersonMenuOverlay'

function channelMemberStatus(member) {
  if (member?.invited && member?.invite_accepted_at) {
    return i18n.t('chat.invite-accepted.text', 'Accepted')
  }
  if (member?.invited && member?.invite_rejected_at) {
    return i18n.t('chat.invite-rejected.text', 'Rejected')
  }
  if (member?.invited) {
    return i18n.t('chat.invite-pending.text', 'Pending')
  }
  return null
}

export default function ChatPersonObject({ person, showMenu }) {
  const [t] = useTranslation()
  const overlay = useOverlay()
  const targetRef = useRef()
  const displayName = person?.user?.name || t('chat.unknown-name.label', 'Unknown Name')
  const portraitUrl = getPortraitUrlFromCisId(person?.user?.fs_cis_id)
  const isOnline = person?.user?.online
  const personStatus = channelMemberStatus(person)

  return (
    <>
      <ListItem
        ref={targetRef}
        data-testid="chat-group-person"
        startElement={chatAvatar({ src: portraitUrl, isInList: true, name: displayName, isOnline })}
        endElement={
          showMenu && <ChatPersonMenuOverlay targetRef={targetRef} person={person} contactOverlay={overlay} />
        }
        primaryText={displayName}
        secondaryText={personStatus}
        onClick={showMenu ? undefined : overlay.handleClick}
      />
      {(overlay.isOpen || overlay.transitioning) && (
        <ContactOverlay contact={{ cisId: person?.user?.fs_cis_id }} overlay={overlay} disableAbout />
      )}
    </>
  )
}
