import React from 'react'
import { MenuMore, NoticeDoNot, NoticeInfo } from '@fs/zion-icon'
import { ListItem, MenuOverlay, useMenuOverlay } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { isUserBlocked } from '../helpers/stream/streamChatHelper'
import useChatBlockUser from '../hooks/useChatBlockUser'
import { useChatState } from '../providers/ChatStateProvider'

export default function ChatPersonMenuOverlay({ targetRef, person, contactOverlay }) {
  const [t] = useTranslation()
  const { client } = useChatState()
  const personUserId = person?.user?.id
  const personName = person?.user?.name
  const menuOverlay = useMenuOverlay()
  const isBlocked = isUserBlocked({ client, userId: personUserId })
  const { unblockUser } = useChatBlockUser({ targetUserId: person?.user?.id, targetUserName: person?.user?.name })

  return (
    <>
      <ListItem.IconButton
        Icon={MenuMore}
        aria-label={t('chat.person-menu.aria-label', 'Chat Person Menu')}
        data-testid="chat-person-menu"
        {...menuOverlay.menuButtonProps}
      />
      <MenuOverlay {...menuOverlay} inline={false}>
        <ListItem
          data-testid="individual-details"
          onClick={() => contactOverlay.open({ target: targetRef.current })}
          primaryText={t('chat.details.action', 'Details')}
          startElement={<ListItem.Icon Icon={NoticeInfo} />}
        />
        {isBlocked && (
          <ListItem
            data-testid="chat-unblock-user"
            onClick={unblockUser}
            primaryText={t('chat.unblock-person.action', `Unblock ${personName}`)}
            startElement={<ListItem.Icon Icon={NoticeDoNot} />}
          />
        )}
      </MenuOverlay>
    </>
  )
}
